namespace Forge.Api.Data.TrainingContent;

public class QuotesTraining : TrainingContentBase
{
    public QuotesTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quotes Overview",
            Slug = "quotes-overview",
            Summary = "What quotes are, how they differ from estimates, line item structure, lifecycle statuses, and conversion to sales orders.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/quotes"]""",
            Tags = """["quotes","sales"]""",
            ContentJson = """{"body":"## Quotes Overview\n\nThe Quotes module manages binding fixed-price commitments to your customers. A quote is a formal document that lists specific parts, quantities, and unit prices — once accepted by the customer, it becomes the contractual basis for a sales order.\n\n### Quotes vs Estimates\n\nForge has two distinct pricing documents, both stored in the same underlying table but serving different purposes:\n\n- **Estimates** are lighter-weight, customer-scoped pricing documents. They start from a single ballpark amount but can also be itemized with line items (catalog parts and/or free-text lump-sum lines). They have no tax calculation and no sales-order conversion of their own. Estimates live on the customer detail page under the Estimates tab.\n- **Quotes** are binding fixed-price commitments. They are line-itemized (each line specifies a part, quantity, and unit price), carry a tax rate, have a formal lifecycle (Draft → Sent → Accepted → Converted to Order), and can be converted into a sales order.\n\nAn estimate can be converted into a quote when the customer wants to move forward. The resulting quote retains a link back to the source estimate for traceability.\n\n### Line Items\n\nEvery quote must have at least one line item. Each line specifies:\n- **Part** — selected from your parts catalog via autocomplete search (optional — a line can also be a free-text description with no part)\n- **Description** — auto-filled from the part record; editable\n- **Quantity** — how many units (fractional quantities to four decimals are allowed)\n- **Unit Price** — defaults to the customer's resolved price for the part when one is configured; can be overridden\n- **Line Total** — calculated as Quantity × Unit Price\n\nThe quote's financial summary is computed from its lines:\n- **Subtotal** — sum of all line totals\n- **Tax** — subtotal multiplied by the tax rate (auto-filled from the customer's state; editable)\n- **Grand Total** — subtotal plus tax\n\n### Editing Line Items on a Draft\n\nYou can add line items two ways: in the create dialog when first building the quote, and — more often — from the **quote detail panel** after the quote is saved. While a quote is in **Draft** status, the Line Items section of the detail panel shows an **Add Line** button plus per-line **Edit** (pencil) and **Delete** (trash) actions:\n\n- **Add Line** opens an inline form with a part picker, description, quantity, and unit price. Picking a catalog part prefills the description and resolves the customer-specific unit price automatically.\n- **Edit** opens the same inline form pre-filled for that row (the part itself isn't changed on edit — only description, quantity, and price).\n- **Delete** removes the line after a confirmation dialog.\n\nEvery add/edit/delete recomputes the subtotal, tax, and total immediately. Once a quote leaves Draft (Sent, Accepted, etc.), the Add Line button and the per-line Edit/Delete actions disappear — the line items become read-only to preserve the integrity of what was sent to the customer.\n\n### Per-Line Margin and Cost Breakdown\n\nWhen a quote line was priced from the estimating engine, the detail panel surfaces profitability for that line:\n\n- A **Margin %** column shows the line's effective margin, computed as (price − cost) ÷ price. Lines that were priced manually (no underlying cost) show a dash (—) instead of a percentage.\n- An expandable **cost breakdown** row beneath the line itemizes the cost components: **Labor**, **Burden**, **Material**, **OSP** (outside processing / subcontract), and a **Total** cost. This lets you see exactly what the quoted price is covering and how much margin it carries.\n\nThe breakdown is informational — it doesn't appear on the customer-facing quote, only in the internal detail panel.\n\n### Quote Lifecycle\n\nQuotes follow a defined status progression:\n\n1. **Draft** (grey) — Initial state. The quote can be edited, lines added or removed, and deleted if no longer needed.\n2. **Sent** (blue) — The quote has been sent to the customer, using the Send button. Records the sent date.\n3. **Accepted** (green) — The customer has accepted the quote, using the Accept button. Records the accepted date.\n4. **Declined** (red) — The customer declined the quote. Set with the Reject button, which asks you to confirm first.\n5. **Expired** (yellow) — The quote passed its expiration date without being accepted.\n6. **Converted to Order** (purple) — The accepted quote has been converted into a sales order. The quote links to the resulting sales order.\n\n### Status Transition Rules\n\n- **Send** is available only when status is Draft\n- **Accept** and **Reject** are available only when status is Sent\n- **Convert to Order** is available only when status is Accepted\n- **Delete** is available only when status is Draft (soft delete)\n- **Line items are editable only while in Draft** — Add Line and per-line Edit/Delete vanish once the quote is Sent\n- Quotes cannot move backward in the lifecycle\n\n### Conversion to Sales Order\n\nWhen you convert an accepted quote, the system:\n1. Creates a new sales order with lines matching the quote's line items\n2. Links the quote to the new sales order (visible in the quote detail as \"Linked Order\")\n3. Updates the quote status to Converted to Order\n4. The sales order inherits the customer, shipping address, and line item details\n\n### Tax Rate Auto-Fill\n\nWhen you select a customer on the quote form, the system looks up the applicable sales tax rate based on the customer's state. The tax rate field is auto-filled with this value (shown with a badge like \"CA 7.25%\"). You can manually override the rate if needed.\n\n### When to Use Quotes\n\n- When a customer requests formal pricing with specific parts and quantities\n- When you need a binding price commitment before creating a sales order\n- When converting an estimate into a detailed line-itemized proposal\n- When you need to track the acceptance/rejection history of pricing proposals","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quotes — Guided Tour",
            Slug = "quotes-walkthrough",
            Summary = "A guided tour of the quotes list page: search, filters, data table, creating quotes, and viewing quote details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/quotes"]""",
            Tags = """["quotes","sales","walkthrough"]""",
            ContentJson = """{"appRoute":"/quotes","startButtonLabel":"Tour Quotes","steps":[{"element":"[data-testid='new-quote-btn']","popover":{"title":"Start a New Quote","description":"Click here to build a new quote. A window opens with line items on one side and quote details — customer, expiration, tax rate, and notes — on the other. Add at least one line before you can save.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Quotes","description":"Find a quote fast. Type a quote number or customer name, then press Enter to filter the list.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Filter by Status","description":"Show only quotes at a certain stage — Draft, Sent, Accepted, Declined, Expired, or Converted to Order. Pick 'All Statuses' to clear the filter.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"The Quotes List","description":"Every quote appears here, with details such as its number, customer, status, line count, total, and dates. Click any row to open the quote. Click a column heading to sort, or use the gear icon to choose which columns show.","side":"top"}},{"element":"app-data-table","popover":{"title":"Editing a Draft's Lines","description":"Open a Draft quote to edit its lines. In the quote's Line Items section, use 'Add Line' or the edit and delete icons on each row. Adding a line lets you pick a part — which fills in the description and the customer's price — or type a free-text line, then set the quantity and price. Every change updates the subtotal, tax, and total right away. You can only edit lines while the quote is a Draft. Once it's Sent, the lines lock and become view-only.","side":"top"}},{"element":"app-data-table","popover":{"title":"Margin and Costs","description":"Open a quote to see profit at a glance. Lines built from an estimate show a Margin % and let you expand a cost breakdown — labor, burden, material, outside processing, and total. Lines you priced by hand show a dash instead. This detail stays internal and never shows on the customer's copy.","side":"top"}},{"element":"[data-testid='new-quote-btn']","popover":{"title":"How to Build a Quote","description":"Four quick steps: 1) Pick a customer — the tax rate fills in from their state. 2) Search for parts and add them as lines; each part's price fills in automatically. 3) Add an expiration date and notes if you want. 4) Check the subtotal, tax, and grand total, then save.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quotes Field Reference",
            Slug = "quotes-field-reference",
            Summary = "Complete reference for every field, button, status, chip color, validation rule, and action in the Quotes module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/quotes"]""",
            Tags = """["quotes","sales","reference"]""",
            ContentJson = """{"title":"Quotes Field Reference","groups":[{"heading":"Quote Details (New Quote Window)","items":[{"label":"Customer (required)","value":"Pick the customer this quote is for. Choosing one fills in the tax rate from their state."},{"label":"Expiration Date","value":"Optional. The date the quote lapses if the customer doesn't accept it. After this date, you can mark the quote Expired."},{"label":"Tax Rate (required)","value":"Fills in from the customer's state (shown with a small tag like 'CA 7.25%'), and you can change it. It's applied to the subtotal to work out the tax. Starts at 0."},{"label":"Notes","value":"Optional. Free-text notes that show on the quote's detail view."}]},{"heading":"Line Fields (New Quote Window)","items":[{"label":"Part (required)","value":"Search by part number or description. Picking a part fills in the unit price from its list price (marked with a 'LIST' tag)."},{"label":"Qty (required)","value":"How many of this part. You can enter fractional amounts down to four decimals."},{"label":"Price (required)","value":"The price per part. Fills in from the part's list price when you pick a part, and you can change it. Can't be negative."},{"label":"Add button","value":"Adds the current part, quantity, and price as a new line. Greyed out until the line is valid, then clears so you can add another."},{"label":"Remove (X) button","value":"The red button on each row. Removes that line from the quote."}]},{"heading":"Totals (New Quote Window)","items":[{"label":"Subtotal","value":"The sum of every line's total (quantity times price). Calculated for you."},{"label":"Tax","value":"The subtotal times the tax rate. Calculated for you."},{"label":"Total","value":"The subtotal plus tax, shown in bold. Calculated for you."}]},{"heading":"Quote Statuses","items":[{"label":"Draft (grey)","value":"The starting point. You can still edit, send, or delete the quote."},{"label":"Sent (blue)","value":"The quote has gone to the customer, and the sent date is recorded. You can accept or reject it."},{"label":"Accepted (green)","value":"The customer accepted, and the date is recorded. You can turn it into a sales order."},{"label":"Declined (red)","value":"The customer said no. This is the end of the road — no more actions."},{"label":"Expired (yellow)","value":"The quote passed its expiration date without being accepted. This is a final state."},{"label":"Converted to Order (purple)","value":"The quote became a sales order, with a link to that order. This is a final state."}]},{"heading":"List Columns","items":[{"label":"Quote #","value":"The quote's number, generated for you. Sortable."},{"label":"Customer","value":"The customer's name. Sortable."},{"label":"Status","value":"A colored label showing where the quote stands. Sortable and filterable."},{"label":"Lines","value":"How many lines are on the quote. Sortable."},{"label":"Total","value":"The grand total (subtotal plus tax), shown as currency. Sortable."},{"label":"Expires","value":"The expiration date, or '---' if none is set. Sortable."},{"label":"Created","value":"The date the quote was created. Sortable."}]},{"heading":"Detail View Fields","items":[{"label":"Quote Number","value":"Shown in the header. Generated for you and not editable."},{"label":"Customer","value":"A link you can click to open the customer's page."},{"label":"Status","value":"A colored label in the info area."},{"label":"Expiration Date","value":"Shown if one is set."},{"label":"Sent Date","value":"Shown once the quote has been sent."},{"label":"Accepted Date","value":"Shown once the quote has been accepted."},{"label":"Linked Order","value":"Shown after conversion — a link you can click to open the sales order."},{"label":"Notes","value":"Shown only if notes were added."},{"label":"Line Items Table","value":"Lists each line's part number, description, quantity, unit price, margin, and total. While the quote is a Draft, edit and delete controls also appear."},{"label":"Subtotal / Tax / Total","value":"The money summary below the lines."},{"label":"Created / Updated","value":"When the quote was created and last changed."},{"label":"Activity Log","value":"A running history of the quote, shown at the bottom of the detail view."}]},{"heading":"Editing Lines on a Draft","items":[{"label":"When you can edit","value":"You can add, edit, and delete lines only while the quote is a Draft. In any other status — Sent, Accepted, Declined, Expired, or Converted to Order — the lines are view-only."},{"label":"Add Line button","value":"Opens a small form below the lines to add one. Greyed out while you're already editing another line."},{"label":"Add form — Part (optional)","value":"Search the parts catalog (shown only when adding, not editing). Picking a part fills in the description if it's blank and the customer's price. Leave it empty for a free-text line."},{"label":"Add form — Description (required)","value":"A short description of the line."},{"label":"Add form — Qty (required)","value":"How many. You can enter fractional amounts down to four decimals."},{"label":"Add form — Unit Price (required)","value":"The price per unit. Fills in from the customer's price list when you pick a part, and you can change it. Can't be negative."},{"label":"Add form — Save / Cancel","value":"Save keeps the change and updates the totals; it's greyed out until the form is valid. Cancel closes the form without saving."},{"label":"Edit (pencil)","value":"Reopens the row so you can change its description, quantity, and price. The part itself stays the same."},{"label":"Delete (trash)","value":"Removes the line after you confirm, then updates the totals."}]},{"heading":"Margin & Cost Breakdown","items":[{"label":"Margin column","value":"Each line's margin — how much of the price is profit — shown as a percentage. Only lines built from an estimate show a number; lines you priced by hand show a dash."},{"label":"Cost breakdown","value":"Expand a line to see what makes up its cost: labor, burden, material, outside processing, and total. Shows only when the line has this detail, and it never appears on the customer's copy."}]},{"heading":"Buttons and Actions","items":[{"label":"New Quote (list page)","value":"Opens the window to build a new quote."},{"label":"Save / Create Quote","value":"Creates the quote. Greyed out until the form is valid and has at least one line. Hover to see what's still needed."},{"label":"Cancel","value":"Closes the new-quote window without saving."},{"label":"Send","value":"Marks the quote Sent. Available only while it's a Draft."},{"label":"Accept","value":"Marks the quote Accepted. Available only once it's been Sent."},{"label":"Reject","value":"Marks the quote Declined. Available only once it's been Sent, and asks you to confirm first."},{"label":"Convert to Order","value":"Turns the accepted quote into a sales order and links the two. Available only once it's Accepted."},{"label":"Delete","value":"Removes the quote. Available only while it's a Draft, and asks you to confirm first."},{"label":"Close","value":"Closes the detail view."},{"label":"Row click","value":"Opens the quote you click on."}]},{"heading":"Validation Rules","items":[{"label":"Customer","value":"Required. Pick a customer before saving."},{"label":"Tax Rate","value":"Required. Enter a number of 0 or more, as a percentage (for example, 7.25 for 7.25%)."},{"label":"Line Items","value":"At least one line is required. Until you add one, Save stays greyed out and a note tells you a line is needed."},{"label":"Line — Part","value":"Required on each line. Pick a part from the search."},{"label":"Line — Quantity","value":"Required. Must be at least a tiny fraction — you can go down to four decimals."},{"label":"Line — Unit Price","value":"Required. Can't be negative."},{"label":"Expiration Date","value":"Optional. No rules."},{"label":"Notes","value":"Optional. No length limit."}]},{"heading":"Automatic Fill-Ins","items":[{"label":"Tax Rate","value":"Picking a customer looks up their state's sales tax rate and fills it in, with a tag like 'CA 7.25%'. Change the rate yourself and the tag goes away."},{"label":"Unit Price","value":"Picking a part fills in its list price, marked with a 'LIST' tag. Change the price yourself and the tag goes away."},{"label":"After adding a line","value":"The line form clears — part empty, quantity back to 1, price back to 0 — ready for the next one."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quotes Knowledge Check",
            Slug = "quotes-quiz",
            Summary = "Test your knowledge of the Quotes module: lifecycle, line items, statuses, conversion, tax auto-fill, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/quotes"]""",
            Tags = """["quotes","sales","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"qt1","text":"A customer asks for a rough ballpark on a project before committing to specifics. Which document type should you create?","options":[{"id":"a","text":"A Quote with a single line item for the estimated total"},{"id":"b","text":"An Estimate — a non-binding ballpark figure with a single lump-sum amount","isCorrect":true},{"id":"c","text":"A Sales Order with a 'Pending' status"},{"id":"d","text":"A Quote in Draft status with no line items"}],"explanation":"Estimates are non-binding ballpark figures with a single amount. Quotes are binding, line-itemized commitments. Use an Estimate first, then convert it to a Quote when the customer wants detailed pricing."},{"id":"qt2","text":"What is the minimum requirement to save a new quote?","options":[{"id":"a","text":"A customer must be selected and at least one line item must be added","isCorrect":true},{"id":"b","text":"Only a customer selection is required — line items can be added later"},{"id":"c","text":"A customer, expiration date, and at least two line items"},{"id":"d","text":"A quote number must be manually entered along with the customer"}],"explanation":"The save button is disabled until a customer is selected and at least one line item exists. The validation popover shows 'At least one line item is required' if no lines have been added. Quote numbers are auto-generated."},{"id":"qt3","text":"You select 'Acme Corp' as the customer and notice the tax rate auto-fills to 7.25% with a badge showing 'CA 7.25%'. What happened?","options":[{"id":"a","text":"The system looked up the sales tax rate for California (the customer's state) and auto-filled it","isCorrect":true},{"id":"b","text":"7.25% is the default tax rate for all customers"},{"id":"c","text":"The tax rate was copied from Acme Corp's last quote"},{"id":"d","text":"The rate was pulled from the federal tax table"}],"explanation":"When you select a customer, the system looks up the applicable sales tax rate based on the customer's state. The badge (e.g., 'CA 7.25%') confirms the source. You can manually override the rate if needed."},{"id":"qt4","text":"When adding a line item, you select a part and see a 'LIST' badge appear next to the unit price. What does this indicate?","options":[{"id":"a","text":"The price was auto-filled from the part's list/default price and can be overridden","isCorrect":true},{"id":"b","text":"The price is locked and cannot be changed"},{"id":"c","text":"The part is on a special price list for this customer"},{"id":"d","text":"The price includes a volume discount"}],"explanation":"When you select a part, the unit price auto-fills from the part's default/list price. The 'LIST' badge indicates this is the catalog price. Manually editing the price clears the badge — you can always override the default."},{"id":"qt5","text":"A quote is currently in 'Sent' status. Which actions are available?","options":[{"id":"a","text":"Accept and Reject only","isCorrect":true},{"id":"b","text":"Send, Accept, Reject, and Delete"},{"id":"c","text":"Accept, Reject, Convert to Order, and Delete"},{"id":"d","text":"Only Convert to Order"}],"explanation":"When a quote is Sent, only Accept and Reject are available. Send is only for Draft quotes. Convert to Order requires Accepted status. Delete is only available for Draft quotes."},{"id":"qt6","text":"What happens when you click 'Convert to Order' on an accepted quote?","options":[{"id":"a","text":"The system creates a new sales order with lines matching the quote, links the quote to the order, and updates the quote status to Converted to Order","isCorrect":true},{"id":"b","text":"The quote is renamed to a sales order — same record, different label"},{"id":"c","text":"A blank sales order is created and you must manually copy the line items"},{"id":"d","text":"The quote is archived and a notification is sent to create a sales order manually"}],"explanation":"Converting creates a new sales order with lines matching the quote's line items, inheriting the customer and details. The quote links to the new sales order (visible as 'Linked Order' in the detail) and its status changes to Converted to Order."},{"id":"qt7","text":"You want to delete a quote that has already been sent to the customer. Can you?","options":[{"id":"a","text":"Yes — any quote can be deleted at any time"},{"id":"b","text":"No — only Draft quotes can be deleted. Sent, Accepted, Declined, and Expired quotes cannot be deleted.","isCorrect":true},{"id":"c","text":"Yes, but only if the customer hasn't responded within 30 days"},{"id":"d","text":"No — quotes can never be deleted, only archived"}],"explanation":"The Delete action is only available when the quote status is Draft. Once a quote has been sent, it becomes part of the audit trail and cannot be deleted. This ensures you maintain a complete record of all pricing communications."},{"id":"qt8","text":"Which chip color represents a quote that has been declined by the customer?","options":[{"id":"a","text":"Yellow (warning)"},{"id":"b","text":"Gray (muted)"},{"id":"c","text":"Red (error)","isCorrect":true},{"id":"d","text":"Blue (info)"}],"explanation":"Declined quotes show a red label. The full color guide: Draft = grey, Sent = blue, Accepted = green, Declined = red, Expired = yellow, Converted to Order = purple."},{"id":"qt9","text":"An estimate was converted to a quote. Where can you see the link back to the original estimate?","options":[{"id":"a","text":"On the quote's detail view — it keeps a link back to the estimate it came from","isCorrect":true},{"id":"b","text":"There is no link — estimates and quotes are completely separate"},{"id":"c","text":"Nowhere you can see — the link only exists behind the scenes"},{"id":"d","text":"In the customer's activity log only"}],"explanation":"When you turn an estimate into a quote, the new quote keeps a link back to the original estimate. This gives you the full pricing history, from the first ballpark to the formal commitment."},{"id":"qt10","text":"How is the grand total on a quote calculated?","options":[{"id":"a","text":"It is manually entered by the user"},{"id":"b","text":"Subtotal (sum of all line totals) plus Tax (subtotal × tax rate percentage)","isCorrect":true},{"id":"c","text":"Sum of all line quantities multiplied by a single unit price"},{"id":"d","text":"The total from the linked estimate plus a markup percentage"}],"explanation":"The grand total is computed: Subtotal = sum of (Quantity × Unit Price) for each line. Tax = Subtotal × Tax Rate %. Grand Total = Subtotal + Tax. All three values are displayed in the summary section."},{"id":"qt11","text":"You're on the quotes list page and want to see only quotes that have been accepted but not yet converted. How do you filter?","options":[{"id":"a","text":"Use the status filter dropdown and select 'Accepted'","isCorrect":true},{"id":"b","text":"Type 'accepted' in the search box"},{"id":"c","text":"Click the column header to sort by status, then scroll to the Accepted section"},{"id":"d","text":"There is no way to filter by status — you must scan the full list"}],"explanation":"The status filter dropdown on the quotes list page lets you filter by any single status. Select 'Accepted' to see only accepted quotes that haven't been converted yet. The table also supports column-level status filtering via the column header filter."},{"id":"qt12","text":"What columns are visible in the quotes data table by default?","options":[{"id":"a","text":"Quote #, Customer, Status, Lines, Total, Expires, and Created","isCorrect":true},{"id":"b","text":"Quote #, Customer, and Total only"},{"id":"c","text":"Quote #, Customer, Status, Assigned To, Priority, and Due Date"},{"id":"d","text":"Quote #, Description, Amount, Tax, and Grand Total"}],"explanation":"The quotes table shows seven columns: Quote # (monospace), Customer name, Status (color-coded chip), Lines count (center-aligned), Total (currency, right-aligned), Expires (date), and Created (date). All columns are sortable. You can manage column visibility via the gear icon."},{"id":"qt13","text":"You saved a Draft quote and now need to add another line and fix a quantity on an existing one. Where do you do this?","options":[{"id":"a","text":"From the quote detail panel — while the quote is Draft, the Line Items section has an Add Line button plus Edit and Delete actions on each row","isCorrect":true},{"id":"b","text":"You must delete the quote and recreate it with the correct lines"},{"id":"c","text":"Only in the original create dialog, which can be reopened from the table row"},{"id":"d","text":"Line items can never be changed once the quote is saved"}],"explanation":"Line items are editable directly from the detail panel while the quote is in Draft. Add Line opens an inline form (part picker, description, qty, price); each row has a pencil (edit) and trash (delete) icon. Every change recomputes the subtotal, tax, and total. Once the quote is Sent, these controls disappear and the lines become read-only."},{"id":"qt14","text":"On a Draft quote's detail panel, one line shows '42.5%' in the Margin column and an expandable cost breakdown, while another line shows a dash (—) and no breakdown. Why the difference?","options":[{"id":"a","text":"The 42.5% line was priced from the estimating engine so it carries an underlying cost (labor/burden/material/OSP); the dashed line was priced manually with no cost to compute margin against","isCorrect":true},{"id":"b","text":"The dashed line is still loading and will show a percentage shortly"},{"id":"c","text":"The dashed line has zero quantity so margin can't be calculated"},{"id":"d","text":"Margin only shows on the first line of every quote"}],"explanation":"The Margin % column shows (price − cost) ÷ price, but only for lines that carry an underlying cost — those priced from the estimating engine, which also expose the Labor / Burden / Material / OSP / Total cost breakdown. A manually-priced line has no cost basis, so its margin renders as a dash. The breakdown is internal-only and never appears on the customer-facing quote."}]}"""
        });

